import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/auto-tagging.md","filePath":"th-TH/Other/auto-tagging.md","lastUpdated":1781962217000}'),d={name:"th-TH/Other/auto-tagging.md"};function o(n,a,g,p,c,r){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging ตั้งค่าได้ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>ระบบจะสร้าง image tags อัตโนมัติ ซึ่งมีประโยชน์กับ search, random image filtering, public gallery filtering และ age-rating access control</p><h2 id="auto-tagging-ทําอะไรได้บ้าง" tabindex="-1">Auto Tagging ทำอะไรได้บ้าง <a class="header-anchor" href="#auto-tagging-ทําอะไรได้บ้าง" aria-label="Permalink to &quot;Auto Tagging ทำอะไรได้บ้าง&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Generate content tags</td><td>เพิ่ม tags สำหรับคน, ฉาก, objects, art style และ visual content ที่คล้ายกัน</td></tr><tr><td>Generate character tags</td><td>เหมาะกับ anime images และ illustrations</td></tr><tr><td>Add orientation tags</td><td>เพิ่ม <code>landscape</code>, <code>portrait</code> หรือ <code>square</code></td></tr><tr><td>Add image rating</td><td>Save ผล <code>G/S/Q/E</code> สำหรับ general, sensitive, questionable หรือ explicit content</td></tr><tr><td>Auto-tag on upload</td><td>Images ที่เพิ่ง upload จะเข้า tagging flow อัตโนมัติ</td></tr><tr><td>Batch tagging</td><td>เพิ่ม tags ให้ old images ในทุก folders หรือ selected folders</td></tr></tbody></table><h2 id="สิ่งที่ต้องเตรียมก่อน" tabindex="-1">สิ่งที่ต้องเตรียมก่อน <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อน" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อน&quot;">​</a></h2><p>เตรียม Hugging Face Space URL ที่เข้าถึงได้อย่างน้อยหนึ่งรายการ</p><p>วิธีที่แนะนำคือ duplicate Space <code>wd-tagger</code> ของ SmilingWolf ไปไว้ใน Hugging Face account ของคุณเอง:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>ใช้ public Space ชั่วคราวได้ แต่ public Spaces ถูก share โดยผู้ใช้จำนวนมาก อาจมี queue, ช้า หรือ unavailable ได้ Space ที่ duplicate ไว้ใน account ของคุณเองจะเสถียรกว่าสำหรับ auto tagging ระยะยาว</p><h2 id="duplicate-space-ของ-smilingwolf" tabindex="-1">Duplicate Space ของ SmilingWolf <a class="header-anchor" href="#duplicate-space-ของ-smilingwolf" aria-label="Permalink to &quot;Duplicate Space ของ SmilingWolf&quot;">​</a></h2><ol><li>Sign in เข้า Hugging Face</li><li>เปิด <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>คลิกเมนูสามจุดที่มุมขวาบน</li><li>เลือก <code>Duplicate this Space</code></li><li>ใช้ Space name เดิมหรือกำหนดเอง เช่น <code>wd-tagger</code></li><li>ตั้ง visibility เป็น <code>Public</code> เพื่อให้ ImgBed call ได้ง่าย</li><li>เริ่มจาก free hardware ค่าเริ่มต้นก่อน ค่อย upgrade เมื่อ queueing ชัดเจน</li><li>Create Space แล้วรอ build เสร็จ</li></ol><p>หลัง build เสร็จ เปิด Space page ของคุณ URL มักมีรูปแบบ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Copy browser URL แล้ว paste ใน <code>Space URLs</code> ของ ImgBed</p><h2 id="ใส่-multiple-space-urls" tabindex="-1">ใส่ Multiple Space URLs <a class="header-anchor" href="#ใส่-multiple-space-urls" aria-label="Permalink to &quot;ใส่ Multiple Space URLs&quot;">​</a></h2><p>ใส่หนึ่ง Space URL ต่อหนึ่ง line</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space เหมาะกับ temporary testing</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Copied Space page URL</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Space ที่คุณ duplicate เอง</td></tr></tbody></table><p>ใส่ได้หลาย URLs ImgBed จะใช้หลาย Spaces ร่วมกัน ซึ่งช่วยเพิ่ม speed ได้</p><p>ถ้า Space หนึ่ง temporarily unavailable อีก Space ยัง process ต่อได้</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>ใส่ Space URLs ที่เตรียมไว้ อย่างน้อยหนึ่งรายการ</td></tr><tr><td>Target folder</td><td>เว้นว่างเพื่อใช้กับทุก folders เลือก folder เฉพาะเมื่อต้องการ process directory บางชุด</td></tr><tr><td>Recognition model</td><td>ใช้ <code>wd-swinv2-tagger-v3</code> เป็นค่าเริ่มต้น</td></tr><tr><td>General tag threshold</td><td>ค่า default เหมาะกับ images ส่วนใหญ่ ค่าต่ำให้ tags มากขึ้น ค่าสูงให้ tags น้อยลง</td></tr><tr><td>Character tag threshold</td><td>ค่า default ค่อนข้าง conservative และช่วยลด character tags ที่ผิด</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>เริ่มต้นให้ off เปิดเมื่ออยากให้ model ตัดสินจำนวน tags เอง</td></tr><tr><td>Auto-tag on upload</td><td>เปิดถ้าต้องการให้ newly uploaded images ได้ tags อัตโนมัติ</td></tr><tr><td>Start tagging</td><td>Batch-tag old images แบบ manual</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>เริ่มต้น Off</td></tr><tr><td>Auto-tag on upload</td><td>Enable หากต้องการ</td></tr></tbody></table><p>ถ้า tags มากเกินไป ให้เพิ่ม general threshold เล็กน้อย</p><p>ถ้า tags น้อยเกินไป ให้ลด general threshold เล็กน้อย</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>กรอก <code>Space URLs</code></li><li>เลือก target folder</li><li>คลิก start tagging</li><li>รอ progress จนเสร็จ</li></ol><p>ถ้า target folder ว่าง ImgBed จะ process ทุก folders</p><p>Batch tagging เหมาะกับ old images สำหรับ new images ให้ enable auto-tag on upload เพื่อไม่ต้อง run เองทุกครั้ง</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>หลัง enable auto-tag on upload Images ที่ upload ใหม่จะ call <code>Space URLs</code> ที่ configure ไว้อัตโนมัติ</p><p>เหมาะกับการใช้งานระยะยาว</p><p>ถ้า Space กำลัง queue อยู่ upload อาจเสร็จก่อน แล้ว tagging จะทำต่อภายหลัง</p><h2 id="images-ใดจะถูก-process" tabindex="-1">Images ใดจะถูก Process <a class="header-anchor" href="#images-ใดจะถูก-process" aria-label="Permalink to &quot;Images ใดจะถูก Process&quot;">​</a></h2><p>Auto tagging process image files เป็นหลัก</p><p>Images ที่มี tags, orientation, rating, width และ height ครบแล้วจะถูก skip เพื่อเลี่ยง Space calls ที่ไม่จำเป็น</p><p>ImgBed จะเติมเฉพาะข้อมูลที่ขาดเมื่อทำได้ เช่น ถ้าขาดแค่ orientation ก็จะพยายามเพิ่ม orientation โดยไม่เรียก full content tag flow</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ทําไมควร-duplicate-space-เอง" tabindex="-1">ทำไมควร Duplicate Space เอง? <a class="header-anchor" href="#ทําไมควร-duplicate-space-เอง" aria-label="Permalink to &quot;ทำไมควร Duplicate Space เอง?&quot;">​</a></h3><p>Public Spaces ถูก share โดยผู้ใช้จำนวนมาก Space ที่ duplicate เองจะถูกใช้โดย ImgBed site ของคุณเป็นหลัก จึงมักเร็วและ reliable กว่า</p><h3 id="space-ขึ้น-starting-up-บ่อย" tabindex="-1">Space ขึ้น Starting Up บ่อย <a class="header-anchor" href="#space-ขึ้น-starting-up-บ่อย" aria-label="Permalink to &quot;Space ขึ้น Starting Up บ่อย&quot;">​</a></h3><p>หลังสร้างครั้งแรก หรือหลัง idle นาน Space อาจต้องใช้เวลาสตาร์ท</p><p>เปิด Space page ของคุณก่อน เมื่อ recognize image ได้ปกติแล้วค่อยกลับมา ImgBed และ start tagging</p><h3 id="copy-space-url-อย่างไร" tabindex="-1">Copy Space URL อย่างไร? <a class="header-anchor" href="#copy-space-url-อย่างไร" aria-label="Permalink to &quot;Copy Space URL อย่างไร?&quot;">​</a></h3><p>เปิด Hugging Face Space page แล้ว copy browser address</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="เพิ่ม-multiple-spaces-ได้ไหม" tabindex="-1">เพิ่ม Multiple Spaces ได้ไหม? <a class="header-anchor" href="#เพิ่ม-multiple-spaces-ได้ไหม" aria-label="Permalink to &quot;เพิ่ม Multiple Spaces ได้ไหม?&quot;">​</a></h3><p>ได้ ใส่หนึ่ง Space URL ต่อหนึ่ง line</p><p>Multiple Spaces process images ร่วมกัน เหมาะเมื่อมี images จำนวนมาก</p><h3 id="ทําไม-tags-เป็น-english" tabindex="-1">ทำไม Tags เป็น English? <a class="header-anchor" href="#ทําไม-tags-เป็น-english" aria-label="Permalink to &quot;ทำไม Tags เป็น English?&quot;">​</a></h3><p>SmilingWolf models output English tags เป็นพฤติกรรมปกติ</p><p>Tags ใช้หลัก ๆ สำหรับ search, filtering, random image API และ public gallery filters</p><h3 id="rating-tags-ใช้ทําอะไร" tabindex="-1">Rating Tags ใช้ทำอะไร? <a class="header-anchor" href="#rating-tags-ใช้ทําอะไร" aria-label="Permalink to &quot;Rating Tags ใช้ทำอะไร?&quot;">​</a></h3><p>Rating results ทำงานร่วมกับ access mode ใน Security Settings</p><p>เช่น เมื่อ visitor access ถูกจำกัดด้วย age rating public browsing และ random image features จะ filter images ตาม rules เหล่านั้น</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in เข้า Hugging Face</span></span>
<span class="line"><span>-&gt; เปิด SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; รอ Space build เสร็จ</span></span>
<span class="line"><span>-&gt; Copy Space URL ของคุณ</span></span>
<span class="line"><span>-&gt; ใส่ Space URLs ใน ImgBed</span></span>
<span class="line"><span>-&gt; เลือก model และ thresholds</span></span>
<span class="line"><span>-&gt; Start tagging หรือ enable auto-tag on upload</span></span></code></pre></div>`,63)])])}const b=e(d,[["render",o]]);export{m as __pageData,b as default};
